wolfram_code:
Module[{b3 = 24, dimsPerPair = 2, dTime = 1, dSampler = 2, pairs, dCore, dBulk = 27, countOk, derivOk, dimOk, bulkOk, sigOk, dSpacelike},
  (* Derive pairs from Betti number *)
  pairs = b3/2;
  dCore = pairs * dimsPerPair;
  dSpacelike = dCore + dSampler;
  (* Check 1: Pair count *)
  countOk = (pairs == 12);
  (* Check 2: Derivation from b3 *)
  derivOk = (pairs == b3/2);
  (* Check 3: pairs x 2 = 24D physics core *)
  dimOk = (dCore == 24);
  (* Check 4: 24 + 1 + 2 = 27D total bulk *)
  bulkOk = (dCore + dTime + dSampler == dBulk);
  (* Check 5: Signature (26,1) *)
  sigOk = (dSpacelike == 26) && (dSpacelike + dTime == dBulk);
  {pairs, dCore, dBulk, countOk, derivOk, dimOk, bulkOk, sigOk,
   If[countOk && derivOk && dimOk && bulkOk && sigOk, "LOCKED", "FAILED"]}
]
